&lt;ul&gt;
&lt;li class=&quot;p1&quot;&gt;&lt;span class=&quot;s1&quot;&gt;A&lt;span class=&quot;Apple-converted-space&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;strong&gt;Bachelor’s or Master’s degree in Computer Science, Mathematics, or related field&lt;/strong&gt;&lt;/li&gt;
&lt;li class=&quot;p1&quot;&gt;Strong programming ability in&lt;span class=&quot;Apple-converted-space&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span class=&quot;s1&quot;&gt;&lt;strong&gt;Rust&lt;/strong&gt;&lt;/span&gt;&lt;span class=&quot;Apple-converted-space&qu
